  // Here we need to ensure indices are within [0, size - 1]
  if (x < 0 || x >= width_ || y < 0 || y >= height_ || z < 0 || z >= depth_) {
    throw std::out_of_range("Indices are out of bounds");
  }
  current_index_ = GetIndex(x, y, z);
