```cpp
#include <iostream>
#include <vector>
#include <algorithm>

const int MAX_N = 10001; // Максимальный размер, согласно условиям задачи.

// Простая структура для хранения файлов и количества их встречаемости.
struct FileCounter {
    std::string name;
    int count;
};

// Функция для проверки равенства имён файлов при сортировке.
bool compareByName(const FileCounter& a, const FileCounter& b) {
    return a.name < b.name;
}

int main() {
    int n, scores[3] = {0}; // scores для хранения баллов каждого студента.
    std::cin >> n;
    std::vector<FileCounter> files(3 * n);

    // Заполняем файлы.
    for (int i = 0; i < 3 * n; i++) {
        std::cin >> files[i].name;
        files[i].count = 0;
    }

    // Сортируем файлы по имени.
    std::sort(files.begin(), files.end(), compareByName);

    // Подсчитываем встречаемость имен.
    for (int i = 0, j; i < 3 * n; i++) {
        j = i + 1;
        while (j < 3 * n && files[i].name == files[j].name) {
            ++j;
        }
        int count = j - i; // Количество повторений текущего имени файла.

        // Начисляем баллы в зависимости от количества встречаемости.
        if (count == 1) {
            scores[i % 3] += 3;
        } else if (count == 2) {
            scores[i % 3] += 1;
            scores[(i + 1) % 3] += 1;
            i++; // Пропускаем следующий файл, потому что он такой же.
        }
        // Если count == 3, никому баллы не начисляются.
        i = j - 1; // Перемещаем индекс i так, чтобы пропустить все повторения.
    }

    // Выводим баллы каждого студента.
    for (int i = 0; i < 3; ++i) {
        std::cout << scores[i] << ' ';
    }

    return 0;
}
```

