Если вы не можете использовать сортировки, а также стандартные ассоциативные контейнеры, такие как `set` и `map`, вы можете решить эту задачу, используя бинарное поисковое дерево (BST), которое вы создадите самостоятельно. Однако стоит учесть, что реализация полноценного бинарного поискового дерева с балансировкой достаточно объемна для этой задачи, поэтому приведу пример реализации простого несбалансированного BST, которое может работать неэффективно в худшем случае.

В этом примере мы создадим очень простое бинарное дерево поиска без балансировки и будем использовать его для подсчета количества каждого названия файла. Используя этот метод, может возникнуть проблема производительности в случае, если названия файлов будут добавляться в дерево таким образом, что оно примет форму вырожденного дерева (например, если имена файлов сортированы). Но для случайных данных это решение должно работать быстро.

```cpp
#include <iostream>
#include <string>

// Узел бинарного дерева поиска, которое хранит название файла и счетчик.
struct BSTNode {
    std::string fileName;
    int count[3] = {0};
    BSTNode* left = nullptr;
    BSTNode* right = nullptr;

    BSTNode(const std::string& name) : fileName(name) {}

    ~BSTNode() {
        delete left;
        delete right;
    }
};

// Вставка узла в бинарное дерево поиска или увеличение счетчика, если файл уже существует.
void insert(BSTNode*& rootNode, const std::string& fileName, int student) {
    if (!rootNode) {
        rootNode = new BSTNode(fileName);
        rootNode->count[student]++;
        return;
    }

    if (fileName < rootNode->fileName) {
        insert(rootNode->left, fileName, student);
    } else if (fileName > rootNode->fileName) {
        insert(rootNode->right, fileName, student);
    } else {
        rootNode->count[student]++;
    }
}

// Обход дерева для подсчета баллов.
void countScores(BSTNode* node, int* scores) {
    if (!node) return;

    countScores(node->left, scores);

    int studentsWithFile = node->count[0] + node->count[1] + node->count[2];
    if (studentsWithFile == 1) {
        for (int i = 0; i < 3; ++i) {
            if (node->count[i] == 1) scores[i] += 3;
        }
    } else if (studentsWithFile == 2) {
        for (int i = 0; i < 3; ++i) {
            if (node->count[i] == 1) scores[i] += 1;
        }
    }
    // Если studentsWithFile == 3, никому не начисляем баллы.

    countScores(node->right, scores);
}

int main() {
    int n;
    std::cin >> n;

    BSTNode* root = nullptr;
    for (int student = 0; student < 3; ++student) {
        for (int i = 0; i < n; ++i) {
            std::string fileName;
            std::cin >> fileName;
            insert(root, fileName, student);
        }
    }

    int scores[3] = {0};
    countScores(root, scores);

    for (int i = 0; i < 3; ++i) {
        std::cout << scores[i] << ' ';
    }

    // Удаление всего дерева.
    delete root;

    return 0;
}
