Обратите внимание, что в этой реализации мы освобождаем память, занимаемую узлами дерева, после того, как подсчитаем баллы. Скорость работы такого дерева зависит от распределения входных данных. Без балансировки дерево может выродиться в связный список (линейный список), что приведет к времени работы O(n^2) при вставке и подсчете баллов, но в среднем случае (если значения вставляются в случайном порядке) оно будет работать гораздо быстрее.

Для решения этой задачи нужно просканировать строку с поданной на вход последовательностью команд и чисел, чтобы построить дерево. Затем пройти по дереву и найти поддерево, которое является бинарным поисковым деревом (BST) с максимальной суммарной пользой от вершин. Условия задачи неполные, так как не очень ясно, какие операции можно использовать для "подъёма наверх", но мы предполагаем, что помимо понятия текущей вершины, у нас имеется ссылка на родителя.

Для начала напишем структуру `Node`, которая будет представлять один узел в дереве:

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

struct Node {
    int value;
    Node *left;
    Node *right;
    Node *parent;

    Node(int v) : value(v), left(nullptr), right(nullptr), parent(nullptr) {}
};

// Функция построения дерева согласно вводу.
Node* BuildTree(const std::vector<std::string>& commands) {
    Node* root = nullptr;
    Node* current = nullptr;

    for (const std::string& command : commands) {
        if (command == "l" || command == "r") {
            if (!root) continue; // Игнорируем направления, если дерево пустое.
            current = (command == "l") ? current->left : current->right;
        } else if (command == "u") {
            if (current) current = current->parent;
        } else { // Значит, это число.
            int value = std::stoi(command);
            Node* node = new Node(value);
            if (!root) {
                root = node; // Устанавливаем корневой узел.
            } else if (!current->left) {
                current->left = node; // Устанавливаем левого ребенка.
            } else {
                current->right = node; // Устанавливаем правого ребенка.
            }
            node->parent = current;
            current = node;
        }
    }

    return root;
}

// Рекурсивная проверка дерева на свойство BST и поиск максимума.
int CheckBSTAndGetSum(Node* node, int& maxSum, int& minVal, int& maxVal) {
    if (!node) return 0;

    // Интервалы значений поддеревьев.
    int leftMin = INT_MAX, rightMax = INT_MIN;
    int leftMax = INT_MIN, rightMin = INT_MAX;

    // Суммы для поддеревьев.
    int leftSum = CheckBSTAndGetSum(node->left, maxSum, leftMin, leftMax);
    int rightSum = CheckBSTAndGetSum(node->right, maxSum, rightMin, rightMax);

    // Устанавливаем текущие минимальное и максимальное значения.
    minVal = std::min(node->value, leftMin);
    maxVal = std::max(node->value, rightMax);

    // Проверяем является ли поддерево BST.
    if ((node->left == nullptr || leftMax < node->value) &&
        (node->right == nullptr || rightMin > node->value)) {
        int totalSum = leftSum + rightSum + node->value;
        maxSum = std::max(maxSum, totalSum);
        return totalSum;
    } else {
        return 0; // Это поддерево не BST.
    }
}

// Основная функция для вычисления максимальной суммы.
int MaxBSTSum(Node* root) {
    int maxSum = 0;
    int minVal, maxVal;
    CheckBSTAndGetSum(root, maxSum, minVal, maxVal);
    return maxSum;
}

void DeleteTree(Node* root) {
    if (root) {
        DeleteTree(root->left);
        DeleteTree(root->right);
        delete root;
    }
}

int main() {
    std::vector<std::string> commands;
    std::string command;
    while (std::cin >> command) {
        commands.push_back(command);
    }

    Node* root = BuildTree(commands);
    int maxSum = (root == nullptr) ? 0 : MaxBSTSum(root);
    std::cout << maxSum << std::endl;

    DeleteTree(root); // Очищаем память.

    return 0;
}
