    if ((node->left == nullptr || (node->left->value < node->value && node->left == node->left->parent->left)) &&
        (node->right == nullptr || (node->right->value > node->value && node->right == node->right->parent->right))) {
        maxSum = std::max(maxSum, totalSum);
        return totalSum;
    }

    return 0; // Если не BST, не включаем этот узел в сумму
}

