#include <iostream>
#include <string>
#include <vector>
#include <limits>

struct Node {
    int value;             // Значение вершины, польза.
    Node* left;            // Указатель на левое поддерево.
    Node* right;           // Указатель на правое поддерево.
    Node* parent;          // Указатель на родительскую вершину.

    Node(int v) : value(v), left(nullptr), right(nullptr), parent(nullptr) {}
};

// Функция для рекурсивного удаления всех узлов дерева.
void DeleteTree(Node* node) {
    if (node) {
        DeleteTree(node->left);
        DeleteTree(node->right);
        delete node;
    }
}

// Функция для проверки, является ли дерево с корнем в данном узле BST.
bool IsBST(Node* node, int minVal, int maxVal) {
    if (!node) return true;
    if (node->value <= minVal || node->value >= maxVal) return false;
    return IsBST(node->left, minVal, node->value) && IsBST(node->right, node->value, maxVal);
}

// Вспомогательная функция для расчета максимальной пользы BST.
int MaxBSTUtil(Node* node, int& maxSum) {
    if (!node) return 0;
    if (!IsBST(node, std::numeric_limits<int>::min(), std::numeric_limits<int>::max())) return 0;

    int sum = node->value + MaxBSTUtil(node->left, maxSum) + MaxBSTUtil(node->right, maxSum);
    maxSum = std::max(maxSum, sum);
    return sum;
}

// Функция для расчета максимальной пользы BST.
int MaxBSTSum(Node* root) {
    int maxSum = 0;  // Переменная для хранения максимальной пользы.
    MaxBSTUtil(root, maxSum);
    return maxSum;  // Возвращаем максимальную пользу.
}

